import { sql } from "@/lib/db"
import { NextResponse } from "next/server"

// GET /api/migrations/bank-v2
// Adds category, category_source, upload_batch_id, source_format to bank_transactions
// and import_source to invoices. Safe to run multiple times (IF NOT EXISTS / ADD COLUMN IF NOT EXISTS).
export async function GET() {
  try {
    await sql`
      ALTER TABLE bank_transactions
        ADD COLUMN IF NOT EXISTS category VARCHAR(100),
        ADD COLUMN IF NOT EXISTS category_source VARCHAR(50),
        ADD COLUMN IF NOT EXISTS upload_batch_id VARCHAR(50),
        ADD COLUMN IF NOT EXISTS source_format VARCHAR(20)
    `

    await sql`
      ALTER TABLE invoices
        ADD COLUMN IF NOT EXISTS import_source VARCHAR(50)
    `

    await sql`
      CREATE INDEX IF NOT EXISTS idx_bank_transactions_batch ON bank_transactions(upload_batch_id)
    `

    return NextResponse.json({
      success: true,
      message: "bank-v2 migration applied: category columns added to bank_transactions, import_source added to invoices",
    })
  } catch (error) {
    console.error("[bank-v2 migration] Error:", error)
    return NextResponse.json(
      { error: error instanceof Error ? error.message : "Migration failed" },
      { status: 500 },
    )
  }
}

// Shared output shape for all bank statement parsers
export interface ParsedBankRow {
  transaction_date: string   // ISO date YYYY-MM-DD
  description: string
  reference_number: string | null
  debit: number | null
  credit: number | null
  balance: number | null
}

// Helper: clean a numeric string like "1,23,456.78" → 123456.78
export function parseAmount(raw: string | undefined | null): number | null {
  if (!raw) return null
  const cleaned = String(raw).replace(/[^0-9.-]/g, "").trim()
  if (!cleaned || cleaned === "-") return null
  const n = parseFloat(cleaned)
  return isNaN(n) ? null : n
}

// Helper: parse a DD/MM/YYYY or DD-MMM-YY or DD-MMM-YYYY date into ISO
export function parseDate(raw: string | undefined | null): string {
  if (!raw) return new Date().toISOString().split("T")[0]

  const s = String(raw).trim()

  // DD/MM/YYYY or DD-MM-YYYY
  const dmy = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/)
  if (dmy) {
    const [, d, m, y] = dmy
    const year = y.length === 2 ? (parseInt(y) > 50 ? `19${y}` : `20${y}`) : y
    return `${year}-${m.padStart(2, "0")}-${d.padStart(2, "0")}`
  }

  // DD-MMM-YY or DD-MMM-YYYY (e.g. 04-MAY-25 or 04-May-2025)
  const dmy2 = s.match(/^(\d{1,2})[\/\-]([A-Za-z]{3})[\/\-](\d{2,4})$/)
  if (dmy2) {
    const months: Record<string, string> = {
      jan:"01",feb:"02",mar:"03",apr:"04",may:"05",jun:"06",
      jul:"07",aug:"08",sep:"09",oct:"10",nov:"11",dec:"12",
    }
    const [, d, mon, y] = dmy2
    const m = months[mon.toLowerCase()] || "01"
    const year = y.length === 2 ? (parseInt(y) > 50 ? `19${y}` : `20${y}`) : y
    return `${year}-${m}-${d.padStart(2, "0")}`
  }

  // Try native Date parse as last resort
  const dt = new Date(s)
  if (!isNaN(dt.getTime())) return dt.toISOString().split("T")[0]

  return new Date().toISOString().split("T")[0]
}

import { type ParsedBankRow, parseAmount, parseDate } from "./types"

// Parse a bank statement CSV file buffer into ParsedBankRow[]
// Handles ICICI bank CSV format as well as generic Date/Description/Debit/Credit/Balance columns
export function parseCsvBank(text: string): ParsedBankRow[] {
  const lines = text.split(/\r?\n/).filter((l) => l.trim())
  if (lines.length < 2) return []

  // Detect header row — skip lines that don't look like headers
  let headerIdx = 0
  for (let i = 0; i < Math.min(10, lines.length); i++) {
    const lower = lines[i].toLowerCase()
    if (lower.includes("date") && (lower.includes("debit") || lower.includes("withdrawal") || lower.includes("credit"))) {
      headerIdx = i
      break
    }
  }

  const headers = lines[headerIdx]
    .split(",")
    .map((h) => h.replace(/"/g, "").trim().toLowerCase())

  const rows: ParsedBankRow[] = []

  for (let i = headerIdx + 1; i < lines.length; i++) {
    // Handle quoted CSV fields
    const values = splitCsvLine(lines[i])
    if (values.length < 2) continue

    const get = (keys: string[]) => {
      for (const k of keys) {
        const idx = headers.findIndex((h) => h.includes(k))
        if (idx >= 0) return values[idx]?.replace(/"/g, "").trim()
      }
      return ""
    }

    const rawDate = get(["date", "txn date", "transaction date", "value date"])
    if (!rawDate) continue

    const row: ParsedBankRow = {
      transaction_date: parseDate(rawDate),
      description: get(["description", "narration", "particulars", "remarks", "transaction details"]) || "",
      reference_number: get(["reference", "ref no", "cheque no", "chq", "utr"]) || null,
      debit: parseAmount(get(["debit", "withdrawal", "dr"])),
      credit: parseAmount(get(["credit", "deposit", "cr"])),
      balance: parseAmount(get(["balance", "closing balance"])),
    }

    // Skip rows that have no monetary data
    if (row.debit === null && row.credit === null) continue

    rows.push(row)
  }

  return rows
}

// Splits a CSV line respecting quoted fields
function splitCsvLine(line: string): string[] {
  const result: string[] = []
  let current = ""
  let inQuotes = false

  for (const char of line) {
    if (char === '"') {
      inQuotes = !inQuotes
    } else if (char === "," && !inQuotes) {
      result.push(current)
      current = ""
    } else {
      current += char
    }
  }
  result.push(current)
  return result
}

import * as XLSX from "xlsx"
import { type ParsedBankRow, parseAmount, parseDate } from "./types"

// Parse an XLS or XLSX bank statement buffer into ParsedBankRow[]
// Handles ICICI savings/current account XLS format
export function parseXlsBank(buffer: Buffer): ParsedBankRow[] {
  const workbook = XLSX.read(buffer, { type: "buffer", cellDates: true })

  // Use the first sheet
  const sheetName = workbook.SheetNames[0]
  const sheet = workbook.Sheets[sheetName]

  // Convert to array-of-arrays to find the header row dynamically
  const aoa: unknown[][] = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: "" })

  // Find header row (contains "date" and some amount column)
  let headerRow = 0
  for (let i = 0; i < Math.min(15, aoa.length); i++) {
    const rowStr = aoa[i].join(" ").toLowerCase()
    if (rowStr.includes("date") && (rowStr.includes("debit") || rowStr.includes("withdrawal") || rowStr.includes("credit"))) {
      headerRow = i
      break
    }
  }

  const headers = (aoa[headerRow] as string[]).map((h) =>
    String(h ?? "").toLowerCase().trim()
  )

  const getIdx = (keys: string[]) => {
    for (const k of keys) {
      const idx = headers.findIndex((h) => h.includes(k))
      if (idx >= 0) return idx
    }
    return -1
  }

  const dateIdx    = getIdx(["date", "txn date", "transaction date", "value date"])
  const descIdx    = getIdx(["description", "narration", "particulars", "remarks"])
  const refIdx     = getIdx(["reference", "ref no", "cheque", "utr"])
  const debitIdx   = getIdx(["debit", "withdrawal", "dr"])
  const creditIdx  = getIdx(["credit", "deposit", "cr"])
  const balanceIdx = getIdx(["balance", "closing"])

  if (dateIdx < 0) return []

  const rows: ParsedBankRow[] = []

  for (let i = headerRow + 1; i < aoa.length; i++) {
    const row = aoa[i] as unknown[]
    const rawDate = row[dateIdx]
    if (!rawDate) continue

    // XLSX may return Date objects when cellDates: true
    let dateStr: string
    if (rawDate instanceof Date) {
      dateStr = rawDate.toISOString().split("T")[0]
    } else {
      dateStr = parseDate(String(rawDate))
    }

    const debit  = debitIdx  >= 0 ? parseAmount(String(row[debitIdx]  ?? "")) : null
    const credit = creditIdx >= 0 ? parseAmount(String(row[creditIdx] ?? "")) : null

    if (debit === null && credit === null) continue

    rows.push({
      transaction_date: dateStr,
      description: descIdx >= 0 ? String(row[descIdx] ?? "").trim() : "",
      reference_number: refIdx >= 0 ? String(row[refIdx] ?? "").trim() || null : null,
      debit,
      credit,
      balance: balanceIdx >= 0 ? parseAmount(String(row[balanceIdx] ?? "")) : null,
    })
  }

  return rows
}

import { type ParsedBankRow, parseAmount, parseDate } from "./types"

// Parse a bank statement PDF buffer into ParsedBankRow[]
// Uses pdf-parse for text extraction, then regex for ICICI format.
// ICICI bank statement lines look like:
//   "20 Jun 2026  UPI-MERCHANT NAME  REF123456  5,000.00   -   1,23,456.78"
// or credit card statement:
//   "04-MAY-25  Late Payment Fee  900.00  900.00"
export async function parsePdfBank(buffer: Buffer): Promise<ParsedBankRow[]> {
  // Dynamically import pdf-parse to avoid issues with Next.js edge bundling
  const pdfParse = (await import("pdf-parse")).default
  const data = await pdfParse(buffer)
  const text = data.text

  return extractRowsFromText(text)
}

function extractRowsFromText(text: string): ParsedBankRow[] {
  const lines = text.split(/\r?\n/).map((l) => l.trim()).filter(Boolean)
  const rows: ParsedBankRow[] = []

  // Regex patterns for different ICICI statement line formats
  // Pattern 1: "DD-MMM-YY  description  amount  amount" (credit card CSV/PDF style)
  const ccPattern = /^(\d{2}-[A-Za-z]{3}-\d{2,4})\s+(.+?)\s+([\d,]+\.\d{2})\s+([\d,]+\.\d{2})\s*$/

  // Pattern 2: "DD Mon YYYY  description  ref  withdrawal  deposit  balance"
  const bankPattern = /^(\d{1,2}\s+[A-Za-z]{3}\s+\d{4})\s+(.+?)\s{2,}([\d,]*\.?\d*)\s+([\d,]*\.?\d*)\s+([\d,]+\.\d{2})\s*$/

  // Pattern 3: Generic amount detection — find lines with a date + amounts
  const genericPattern = /^(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}|\d{1,2}[\/\-][A-Za-z]{3}[\/\-]\d{2,4}|\d{1,2}\s+[A-Za-z]{3}\s+\d{4})\s+(.+?)\s+([\d,]+\.\d{2})\s*$/

  for (const line of lines) {
    // Try bank pattern first (more specific)
    const m2 = line.match(bankPattern)
    if (m2) {
      const [, date, desc, w, d, bal] = m2
      const debit  = parseAmount(w)
      const credit = parseAmount(d)
      if (debit !== null || credit !== null) {
        rows.push({
          transaction_date: parseDate(date),
          description: desc.trim(),
          reference_number: null,
          debit:   debit  && debit  > 0 ? debit  : null,
          credit:  credit && credit > 0 ? credit : null,
          balance: parseAmount(bal),
        })
        continue
      }
    }

    // Try CC pattern
    const m1 = line.match(ccPattern)
    if (m1) {
      const [, date, desc, , amt] = m1
      const amount = parseAmount(amt)
      if (amount !== null) {
        // Negative descriptions (payments/refunds) indicate credits
        const isCredit = desc.toLowerCase().includes("payment received") || desc.toLowerCase().includes("refund")
        rows.push({
          transaction_date: parseDate(date),
          description: desc.trim(),
          reference_number: null,
          debit:  isCredit ? null : amount,
          credit: isCredit ? amount : null,
          balance: null,
        })
        continue
      }
    }

    // Try generic pattern
    const m3 = line.match(genericPattern)
    if (m3) {
      const [, date, desc, amt] = m3
      const amount = parseAmount(amt)
      if (amount !== null && amount > 0) {
        const isCredit = desc.toLowerCase().includes("credit") || desc.toLowerCase().includes("received")
        rows.push({
          transaction_date: parseDate(date),
          description: desc.trim(),
          reference_number: null,
          debit:  isCredit ? null : amount,
          credit: isCredit ? amount : null,
          balance: null,
        })
      }
    }
  }

  return rows
}

import { type NextRequest, NextResponse } from "next/server"
import { sql } from "@/lib/db"
import { getCurrentOrgId } from "@/lib/get-org"
import { categorize, fetchRules } from "@/lib/categorize"
import { parseCsvBank } from "@/lib/parsers/csv-bank"
import { parseXlsBank } from "@/lib/parsers/xls-bank"
import { parsePdfBank } from "@/lib/parsers/pdf-bank"
import { runAutoReconcile } from "@/lib/reconcile-engine"

export const maxDuration = 60 // Vercel function timeout for large files

// POST /api/bank-statements/upload
// Accepts multipart/form-data with a "file" field (CSV, XLS, XLSX, or PDF)
// Returns { inserted, skipped, batchId }
export async function POST(request: NextRequest) {
  try {
    const formData = await request.formData()
    const file = formData.get("file") as File | null

    if (!file) {
      return NextResponse.json({ error: "No file provided" }, { status: 400 })
    }

    const fileName = file.name.toLowerCase()
    const ext = fileName.split(".").pop() ?? ""

    if (!["csv", "xls", "xlsx", "pdf"].includes(ext)) {
      return NextResponse.json(
        { error: `Unsupported file type ".${ext}". Please upload CSV, XLS, XLSX, or PDF.` },
        { status: 400 },
      )
    }

    // Read file into buffer
    const arrayBuffer = await file.arrayBuffer()
    const buffer = Buffer.from(arrayBuffer)

    // Parse based on format
    let rows
    if (ext === "csv") {
      rows = parseCsvBank(buffer.toString("utf-8"))
    } else if (ext === "xls" || ext === "xlsx") {
      rows = parseXlsBank(buffer)
    } else {
      rows = await parsePdfBank(buffer)
    }

    if (rows.length === 0) {
      return NextResponse.json(
        { error: "No transactions could be parsed from this file. Check the format and try again." },
        { status: 422 },
      )
    }

    const orgId = await getCurrentOrgId()
    const rules = await fetchRules(orgId)
    const batchId = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`

    let inserted = 0
    let skipped = 0

    for (const txn of rows) {
      // Skip duplicates: same org + date + description + amount combination
      const exists = await sql`
        SELECT id FROM bank_transactions
        WHERE org_id = ${orgId}
          AND transaction_date = ${txn.transaction_date}
          AND description = ${txn.description}
          AND COALESCE(debit, 0) = COALESCE(${txn.debit}, 0)
          AND COALESCE(credit, 0) = COALESCE(${txn.credit}, 0)
        LIMIT 1
      `
      if (exists.length > 0) { skipped++; continue }

      const { category, source } = categorize(txn.description, rules)

      await sql`
        INSERT INTO bank_transactions (
          org_id, transaction_date, description, reference_number,
          debit, credit, balance, reconciled,
          category, category_source, upload_batch_id, source_format
        ) VALUES (
          ${orgId}, ${txn.transaction_date}, ${txn.description},
          ${txn.reference_number ?? null},
          ${txn.debit ?? null}, ${txn.credit ?? null},
          ${txn.balance ?? null}, false,
          ${category}, ${source}, ${batchId}, ${ext}
        )
      `
      inserted++
    }

    // Run auto-reconciliation on newly inserted batch
    const suggestions = await runAutoReconcile(orgId, batchId)

    return NextResponse.json({
      success: true,
      inserted,
      skipped,
      total: rows.length,
      batchId,
      autoMatched: suggestions.matched,
    })
  } catch (error) {
    console.error("[bank-statements/upload] Error:", error)
    return NextResponse.json(
      { error: error instanceof Error ? error.message : "Upload failed" },
      { status: 500 },
    )
  }
}

import { sql } from "@/lib/db"

// ── Auto-reconciliation engine ────────────────────────────────────────────────
// Runs after every bank statement upload.
// Two matching strategies:
//   1. Income match: bank credit ↔ unpaid invoice (amount within ₹1, date within 30 days)
//   2. Expense match: bank debit with CC payment keywords ↔ unreconciled payment record

export interface ReconcileSuggestion {
  bankTxId: string
  matchType: "income" | "expense"
  invoiceId?: string
  paymentId?: string
  confidence: number   // 0–100
  reason: string
}

// CC payment keywords found in bank statement debit descriptions
const CC_PAYMENT_KEYWORDS = [
  "infinity payment",
  "icici cc",
  "credit card payment",
  "cc payment",
  "creditcard",
]

function daysBetween(a: string, b: string): number {
  const diff = Math.abs(new Date(a).getTime() - new Date(b).getTime())
  return Math.floor(diff / (1000 * 60 * 60 * 24))
}

function amountConfidence(bankAmt: number, matchAmt: number): number {
  const diff = Math.abs(bankAmt - matchAmt)
  if (diff === 0) return 100
  if (diff <= 1) return 98
  if (diff <= 10) return 90
  const pct = diff / bankAmt
  if (pct <= 0.01) return 85
  if (pct <= 0.05) return 70
  return 0
}

// Main entry point — called after upload with the new batch ID
export async function runAutoReconcile(
  orgId: number,
  batchId: string
): Promise<{ matched: number; suggestions: ReconcileSuggestion[] }> {
  // Fetch newly uploaded transactions in this batch
  const newTxns = await sql`
    SELECT id, transaction_date, description, debit, credit, balance
    FROM bank_transactions
    WHERE org_id = ${orgId} AND upload_batch_id = ${batchId} AND reconciled = false
    ORDER BY transaction_date ASC
  `

  const suggestions: ReconcileSuggestion[] = []
  let matched = 0

  for (const txn of newTxns) {
    const txId = String(txn.id)
    const txDate = String(txn.transaction_date).split("T")[0]
    const credit = txn.credit ? Number(txn.credit) : null
    const debit  = txn.debit  ? Number(txn.debit)  : null
    const desc   = String(txn.description ?? "").toLowerCase()

    // ── Income matching: bank credit → unpaid invoice ──────────────────────
    if (credit && credit > 0) {
      const invoices = await sql`
        SELECT id, invoice_number, total_amount, invoice_date, status
        FROM invoices
        WHERE org_id = ${orgId}
          AND status IN ('unpaid', 'partially_paid', 'overdue')
          AND total_amount BETWEEN ${credit - 1} AND ${credit + 1}
        ORDER BY invoice_date DESC
        LIMIT 10
      `

      let bestInvoice: { id: string; invoice_number: string; total_amount: number; invoice_date: string } | null = null
      let bestScore = 0

      for (const inv of invoices) {
        const invDate = String(inv.invoice_date).split("T")[0]
        const days = daysBetween(txDate, invDate)
        const amtScore = amountConfidence(credit, Number(inv.total_amount))
        // Date proximity bonus: within 7 days = full bonus, within 30 = partial
        const dateScore = days <= 7 ? 20 : days <= 30 ? 10 : 0
        const score = amtScore + dateScore

        if (score > bestScore && amtScore > 0) {
          bestScore = score
          bestInvoice = inv as { id: string; invoice_number: string; total_amount: number; invoice_date: string }
        }
      }

      if (bestInvoice && bestScore >= 70) {
        // Create a payment record and reconcile automatically
        const paymentRows = await sql`
          INSERT INTO payments (org_id, invoice_id, client_id, amount, payment_date, payment_method, notes, reconciled)
          SELECT ${orgId}, ${bestInvoice.id}, client_id, ${credit}, ${txDate}, 'bank_transfer',
                 'Auto-matched by reconciliation engine', true
          FROM invoices WHERE id = ${bestInvoice.id}
          RETURNING id
        `
        const paymentId = String(paymentRows[0]?.id)

        await sql`
          UPDATE bank_transactions
          SET reconciled = true, payment_id = ${paymentId}
          WHERE id = ${txId}
        `

        await sql`
          UPDATE invoices SET status = 'paid', updated_at = NOW()
          WHERE id = ${bestInvoice.id}
        `

        suggestions.push({
          bankTxId: txId,
          matchType: "income",
          invoiceId: bestInvoice.id,
          paymentId,
          confidence: bestScore,
          reason: `Matched ₹${credit.toLocaleString("en-IN")} credit to Invoice ${bestInvoice.invoice_number}`,
        })
        matched++
        continue
      }
    }

    // ── Expense matching: CC payment debit → payments table ────────────────
    if (debit && debit > 0) {
      const isCCPayment = CC_PAYMENT_KEYWORDS.some((kw) => desc.includes(kw))

      if (isCCPayment) {
        const payments = await sql`
          SELECT p.id, p.amount, p.payment_date, i.invoice_number
          FROM payments p
          LEFT JOIN invoices i ON p.invoice_id = i.id
          WHERE p.org_id = ${orgId}
            AND p.reconciled = false
            AND p.amount BETWEEN ${debit - 1} AND ${debit + 1}
          ORDER BY ABS(p.amount - ${debit}) ASC
          LIMIT 5
        `

        if (payments.length > 0) {
          const bestPayment = payments[0] as { id: string; amount: number; payment_date: string; invoice_number: string }
          const days = daysBetween(txDate, String(bestPayment.payment_date).split("T")[0])
          const conf = amountConfidence(debit, Number(bestPayment.amount)) + (days <= 2 ? 15 : days <= 7 ? 5 : 0)

          if (conf >= 70) {
            await sql`
              UPDATE bank_transactions
              SET reconciled = true, payment_id = ${bestPayment.id}
              WHERE id = ${txId}
            `
            await sql`
              UPDATE payments SET reconciled = true, updated_at = NOW()
              WHERE id = ${bestPayment.id}
            `

            suggestions.push({
              bankTxId: txId,
              matchType: "expense",
              paymentId: bestPayment.id,
              confidence: conf,
              reason: `CC payment of ₹${debit.toLocaleString("en-IN")} matched to payment record`,
            })
            matched++
          }
        }
      }
    }
  }

  return { matched, suggestions }
}

// Fetch unreconciled summary for notifications
export async function getUnreconciledSummary(orgId: number) {
  const [unreconciled, overdueInvoices] = await Promise.all([
    sql`
      SELECT id, transaction_date, description, credit, debit
      FROM bank_transactions
      WHERE org_id = ${orgId}
        AND reconciled = false
        AND created_at < NOW() - INTERVAL '7 days'
      ORDER BY transaction_date DESC
    `,
    sql`
      SELECT id, invoice_number, total_amount, invoice_date, client_id
      FROM invoices
      WHERE org_id = ${orgId}
        AND status IN ('unpaid', 'overdue')
        AND invoice_date + payment_due_days * INTERVAL '1 day' < NOW()
      ORDER BY invoice_date ASC
    `,
  ])

  return {
    unreconciledCount: unreconciled.length,
    unreconciledTransactions: unreconciled,
    overdueCount: overdueInvoices.length,
    overdueInvoices,
  }
}

"use client"

import type React from "react"
import { useState } from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Upload, FileText, CheckCircle2, AlertCircle, Loader2, Sparkles } from "lucide-react"
import { useRouter } from "next/navigation"

const ACCEPTED = ".csv,.xls,.xlsx,.pdf"
const FORMAT_LABELS: Record<string, string> = {
  csv: "CSV",
  xls: "Excel (XLS)",
  xlsx: "Excel (XLSX)",
  pdf: "PDF",
}

interface UploadResult {
  inserted: number
  skipped: number
  total: number
  autoMatched: number
  batchId: string
}

export function BankStatementUpload() {
  const router = useRouter()
  const [isUploading, setIsUploading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [result, setResult] = useState<UploadResult | null>(null)
  const [file, setFile] = useState<File | null>(null)

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = e.target.files?.[0]
    if (selected) {
      setFile(selected)
      setError(null)
      setResult(null)
    }
  }

  const handleDrop = (e: React.DragEvent<HTMLLabelElement>) => {
    e.preventDefault()
    const dropped = e.dataTransfer.files[0]
    if (dropped) {
      setFile(dropped)
      setError(null)
      setResult(null)
    }
  }

  const handleUpload = async () => {
    if (!file) { setError("Please select a file"); return }

    const ext = file.name.split(".").pop()?.toLowerCase() ?? ""
    if (!["csv", "xls", "xlsx", "pdf"].includes(ext)) {
      setError(`".${ext}" is not supported. Use CSV, XLS, XLSX or PDF.`)
      return
    }

    setIsUploading(true)
    setError(null)
    setResult(null)

    try {
      const formData = new FormData()
      formData.append("file", file)

      const res = await fetch("/api/bank-statements/upload", {
        method: "POST",
        body: formData,
      })

      const json = await res.json()

      if (!res.ok) {
        setError(json.error ?? "Upload failed")
        return
      }

      setResult(json as UploadResult)
      setFile(null)
      // Reset the file input
      const input = document.getElementById("bank-file-upload") as HTMLInputElement
      if (input) input.value = ""
      router.refresh()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Upload failed")
    } finally {
      setIsUploading(false)
    }
  }

  const ext = file?.name.split(".").pop()?.toLowerCase() ?? ""
  const formatLabel = FORMAT_LABELS[ext] ?? "File"

  return (
    <Card>
      <CardHeader>
        <CardTitle>Upload Bank Statement</CardTitle>
        <CardDescription>
          Supports CSV, Excel (XLS/XLSX), and PDF from ICICI and most Indian banks.
          Duplicates are automatically skipped.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {/* Drop zone */}
          <label
            htmlFor="bank-file-upload"
            onDrop={handleDrop}
            onDragOver={(e) => e.preventDefault()}
            className="flex flex-col items-center justify-center gap-2 w-full min-h-[120px] border-2 border-dashed rounded-lg cursor-pointer hover:bg-muted/40 transition-colors px-4 py-6 text-center"
          >
            {file ? (
              <>
                <FileText className="h-8 w-8 text-primary" />
                <span className="text-sm font-medium">{file.name}</span>
                <span className="text-xs text-muted-foreground">{formatLabel} · {(file.size / 1024).toFixed(0)} KB</span>
              </>
            ) : (
              <>
                <Upload className="h-8 w-8 text-muted-foreground" />
                <span className="text-sm font-medium">Drop your bank statement here</span>
                <span className="text-xs text-muted-foreground">CSV · XLS · XLSX · PDF</span>
              </>
            )}
            <input
              id="bank-file-upload"
              type="file"
              accept={ACCEPTED}
              onChange={handleFileChange}
              className="hidden"
              disabled={isUploading}
            />
          </label>

          <Button
            onClick={handleUpload}
            disabled={!file || isUploading}
            className="w-full sm:w-auto"
          >
            {isUploading ? (
              <><Loader2 className="h-4 w-4 mr-2 animate-spin" />Uploading…</>
            ) : (
              <><Upload className="h-4 w-4 mr-2" />Upload Statement</>
            )}
          </Button>

          {/* Error */}
          {error && (
            <div className="flex items-start gap-2 text-sm text-destructive">
              <AlertCircle className="h-4 w-4 mt-0.5 shrink-0" />
              <span>{error}</span>
            </div>
          )}

          {/* Success result */}
          {result && (
            <div className="flex flex-col gap-1 text-sm border rounded-lg p-4 bg-muted/30">
              <div className="flex items-center gap-2 font-medium text-green-700 dark:text-green-400">
                <CheckCircle2 className="h-4 w-4" />
                Upload complete
              </div>
              <span className="text-muted-foreground">
                {result.inserted} new transactions added · {result.skipped} duplicates skipped
              </span>
              {result.autoMatched > 0 && (
                <div className="flex items-center gap-1.5 text-amber-600 dark:text-amber-400 mt-1">
                  <Sparkles className="h-3.5 w-3.5" />
                  <span>{result.autoMatched} transaction{result.autoMatched > 1 ? "s" : ""} auto-reconciled with invoices</span>
                </div>
              )}
            </div>
          )}

          {/* Format hint */}
          {!result && (
            <details className="text-sm text-muted-foreground">
              <summary className="cursor-pointer font-medium mb-2">Expected column names</summary>
              <pre className="bg-muted p-3 rounded-lg text-xs overflow-x-auto">
{`CSV / Excel:
  Date, Description, Debit, Credit, Balance, Reference
  — or ICICI format: Txn Date, Withdrawal Amt, Deposit Amt, Closing Balance

PDF:
  ICICI account/credit card PDF statements are supported.
  Text extraction is automatic.`}
              </pre>
            </details>
          )}
        </div>
      </CardContent>
    </Card>
  )
}

// Parses a bulk invoice import CSV into structured invoice rows.
// Expected columns (case-insensitive, flexible names):
//   invoice_number, client_name, invoice_date, amount_before_tax,
//   cgst_rate, sgst_rate, status, description, hsn_code, terms, payment_due_days

export interface ParsedInvoiceRow {
  invoice_number: string
  client_name: string
  invoice_date: string        // ISO date
  amount_before_tax: number
  cgst_rate: number           // default 9
  sgst_rate: number           // default 9
  cgst_amount: number         // computed
  sgst_amount: number         // computed
  total_amount: number        // computed
  description: string
  hsn_code: string | null
  terms: string | null
  status: "paid" | "unpaid" | "overdue"
  payment_due_days: number    // default 7
}

export interface ParseInvoiceResult {
  rows: ParsedInvoiceRow[]
  errors: Array<{ line: number; message: string }>
}

export function parseInvoiceCsv(text: string): ParseInvoiceResult {
  const lines = text.split(/\r?\n/).filter((l) => l.trim())
  if (lines.length < 2) return { rows: [], errors: [{ line: 1, message: "File is empty or has no data rows" }] }

  const headers = lines[0]
    .split(",")
    .map((h) => h.replace(/"/g, "").trim().toLowerCase().replace(/[\s_-]+/g, "_"))

  const get = (row: string[], keys: string[]): string => {
    for (const k of keys) {
      const idx = headers.findIndex((h) => h === k || h.includes(k.split("_")[0]))
      if (idx >= 0) return row[idx]?.replace(/"/g, "").trim() ?? ""
    }
    return ""
  }

  const rows: ParsedInvoiceRow[] = []
  const errors: Array<{ line: number; message: string }> = []

  for (let i = 1; i < lines.length; i++) {
    const cols = lines[i].split(",").map((c) => c.replace(/"/g, "").trim())

    const invoiceNumber = get(cols, ["invoice_number", "invoice_no", "inv_no", "number"])
    const clientName    = get(cols, ["client_name", "client", "customer", "party"])
    const dateRaw       = get(cols, ["invoice_date", "date", "inv_date"])
    const amtRaw        = get(cols, ["amount_before_tax", "amount", "subtotal", "net_amount", "basic_amount"])
    const description   = get(cols, ["description", "desc", "particulars", "service"])
    const statusRaw     = get(cols, ["status", "payment_status"])
    const cgstRaw       = get(cols, ["cgst_rate", "cgst", "cgst_%"])
    const sgstRaw       = get(cols, ["sgst_rate", "sgst", "sgst_%"])
    const hsnRaw        = get(cols, ["hsn_code", "hsn", "sac"])
    const termsRaw      = get(cols, ["terms", "payment_terms", "notes"])
    const dueDaysRaw    = get(cols, ["payment_due_days", "due_days", "due_in"])

    // Validate required fields
    if (!invoiceNumber) { errors.push({ line: i + 1, message: "Missing invoice_number" }); continue }
    if (!clientName)    { errors.push({ line: i + 1, message: "Missing client_name" }); continue }
    if (!amtRaw)        { errors.push({ line: i + 1, message: "Missing amount" }); continue }

    const amount = parseFloat(amtRaw.replace(/[^0-9.-]/g, ""))
    if (isNaN(amount) || amount < 0) { errors.push({ line: i + 1, message: `Invalid amount: "${amtRaw}"` }); continue }

    // Parse date
    let invoiceDate: string
    try {
      const { parseDate } = await import("./types").catch(() => ({ parseDate: fallbackParseDate }))
      invoiceDate = parseDate(dateRaw || new Date().toISOString())
    } catch {
      invoiceDate = fallbackParseDate(dateRaw)
    }

    const cgstRate = cgstRaw ? parseFloat(cgstRaw) || 9 : 9
    const sgstRate = sgstRaw ? parseFloat(sgstRaw) || 9 : 9
    const cgstAmount = Math.round(amount * (cgstRate / 100) * 100) / 100
    const sgstAmount = Math.round(amount * (sgstRate / 100) * 100) / 100
    const totalAmount = Math.round((amount + cgstAmount + sgstAmount) * 100) / 100

    const validStatuses = ["paid", "unpaid", "overdue"]
    const status = (validStatuses.includes(statusRaw.toLowerCase()) ? statusRaw.toLowerCase() : "unpaid") as ParsedInvoiceRow["status"]

    rows.push({
      invoice_number: invoiceNumber,
      client_name: clientName,
      invoice_date: invoiceDate,
      amount_before_tax: amount,
      cgst_rate: cgstRate,
      sgst_rate: sgstRate,
      cgst_amount: cgstAmount,
      sgst_amount: sgstAmount,
      total_amount: totalAmount,
      description: description || invoiceNumber,
      hsn_code: hsnRaw || null,
      terms: termsRaw || null,
      status,
      payment_due_days: dueDaysRaw ? parseInt(dueDaysRaw) || 7 : 7,
    })
  }

  return { rows, errors }
}

// Sync fallback (used when dynamic import isn't available)
function fallbackParseDate(raw: string): string {
  if (!raw) return new Date().toISOString().split("T")[0]
  const dmy = raw.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/)
  if (dmy) {
    const [, d, m, y] = dmy
    const year = y.length === 2 ? `20${y}` : y
    return `${year}-${m.padStart(2, "0")}-${d.padStart(2, "0")}`
  }
  const dt = new Date(raw)
  return isNaN(dt.getTime()) ? new Date().toISOString().split("T")[0] : dt.toISOString().split("T")[0]
}

// Generate a downloadable CSV template string
export function getInvoiceImportTemplate(): string {
  const header = "invoice_number,client_name,invoice_date,amount_before_tax,cgst_rate,sgst_rate,status,description,hsn_code,terms,payment_due_days"
  const example1 = "INV-001,Acme Corp,01/04/2025,50000,9,9,paid,Web Development Services,9983,,30"
  const example2 = "INV-002,Beta Ltd,15/04/2025,25000,9,9,unpaid,UI/UX Design,9983,Payment due in 30 days,30"
  return [header, example1, example2].join("\n")
}

import { type NextRequest, NextResponse } from "next/server"
import { sql } from "@/lib/db"
import { getCurrentOrgId } from "@/lib/get-org"
import { parseInvoiceCsv, getInvoiceImportTemplate } from "@/lib/parsers/invoice-csv"

// GET /api/invoices/import — download the CSV template
export async function GET() {
  const csv = getInvoiceImportTemplate()
  return new NextResponse(csv, {
    headers: {
      "Content-Type": "text/csv",
      "Content-Disposition": 'attachment; filename="invoice-import-template.csv"',
    },
  })
}

// POST /api/invoices/import — upload a filled-in CSV
// Returns { inserted, skipped, errors }
export async function POST(request: NextRequest) {
  try {
    const formData = await request.formData()
    const file = formData.get("file") as File | null

    if (!file) return NextResponse.json({ error: "No file provided" }, { status: 400 })

    const ext = file.name.split(".").pop()?.toLowerCase() ?? ""
    if (ext !== "csv") {
      return NextResponse.json({ error: "Invoice import only supports CSV files." }, { status: 400 })
    }

    const text = await file.text()
    const { rows, errors } = parseInvoiceCsv(text)

    if (rows.length === 0 && errors.length > 0) {
      return NextResponse.json({ error: "Could not parse any rows", parseErrors: errors }, { status: 422 })
    }

    const orgId = await getCurrentOrgId()
    let inserted = 0
    let skipped = 0

    for (const row of rows) {
      // Find or create client by name
      let clientId: number
      const existingClient = await sql`
        SELECT id FROM clients
        WHERE org_id = ${orgId} AND LOWER(name) = LOWER(${row.client_name})
        LIMIT 1
      `

      if (existingClient.length > 0) {
        clientId = existingClient[0].id as number
      } else {
        const newClient = await sql`
          INSERT INTO clients (org_id, name) VALUES (${orgId}, ${row.client_name}) RETURNING id
        `
        clientId = newClient[0].id as number
      }

      // Skip duplicate invoice numbers
      const exists = await sql`
        SELECT id FROM invoices
        WHERE org_id = ${orgId} AND invoice_number = ${row.invoice_number}
        LIMIT 1
      `
      if (exists.length > 0) { skipped++; continue }

      await sql`
        INSERT INTO invoices (
          org_id, client_id, invoice_number, invoice_date,
          description, hsn_code, amount_before_tax,
          cgst_rate, sgst_rate, cgst_amount, sgst_amount, total_amount,
          terms, status, payment_due_days, import_source
        ) VALUES (
          ${orgId}, ${clientId}, ${row.invoice_number}, ${row.invoice_date},
          ${row.description}, ${row.hsn_code ?? null}, ${row.amount_before_tax},
          ${row.cgst_rate}, ${row.sgst_rate}, ${row.cgst_amount}, ${row.sgst_amount}, ${row.total_amount},
          ${row.terms ?? null}, ${row.status}, ${row.payment_due_days}, 'csv_import'
        )
      `
      inserted++
    }

    return NextResponse.json({
      success: true,
      inserted,
      skipped,
      total: rows.length,
      parseErrors: errors,
    })
  } catch (error) {
    console.error("[invoices/import] Error:", error)
    return NextResponse.json(
      { error: error instanceof Error ? error.message : "Import failed" },
      { status: 500 },
    )
  }
}

"use client"

import type React from "react"
import { useState } from "react"
import { Button } from "@/components/ui/button"
import {
  Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger,
