"use client"

import { useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Check, X, Sparkles, Loader2, ArrowUpCircle, ArrowDownCircle } from "lucide-react"
import type { BankTransaction, Payment } from "@/lib/types"
import { fetchFromAPI } from "@/lib/fetch"
import { useRouter } from "next/navigation"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { CategoryBadge } from "@/components/category-badge"

interface ReconciliationViewProps {
  transactions: (BankTransaction & { payment?: Payment & { invoice?: { invoice_number: string } } })[]
  payments: (Payment & { invoice?: { invoice_number: string } })[]
}

// Suggest a payment match if credit amount is within ±5% of payment amount
function getSuggestedMatch(creditAmount: number, payments: (Payment & { invoice?: { invoice_number: string } })[]) {
  const tolerance = 0.05
  return payments.find((p) => {
    const diff = Math.abs(Number(p.amount) - creditAmount) / creditAmount
    return diff <= tolerance
  })
}

type TabKey = "credits" | "debits" | "reconciled"

export function ReconciliationView({ transactions, payments }: ReconciliationViewProps) {
  const router = useRouter()
  const [selectedPayments, setSelectedPayments] = useState<Record<string, string>>({})
  const [isReconciling, setIsReconciling] = useState<string | null>(null)
  const [activeTab, setActiveTab] = useState<TabKey>("credits")

  const unreconciledCredits = transactions.filter((t) => !t.reconciled && t.credit && Number(t.credit) > 0)
  const unreconciledDebits  = transactions.filter((t) => !t.reconciled && t.debit  && Number(t.debit)  > 0)
  const reconciledTxns      = transactions.filter((t) => t.reconciled)

  const handleReconcile = async (transactionId: string, paymentId: string) => {
    setIsReconciling(transactionId)
    try {
      await fetchFromAPI("/api/reconcile", {
        method: "POST",
        body: JSON.stringify({ transactionId, paymentId }),
      })
      router.refresh()
      setSelectedPayments((prev) => { const s = { ...prev }; delete s[transactionId]; return s })
    } catch (error) {
      console.error("Error reconciling:", error)
    } finally {
      setIsReconciling(null)
    }
  }

  const handleUnreconcile = async (transactionId: string, paymentId: string | null) => {
    setIsReconciling(transactionId)
    try {
      await fetchFromAPI("/api/reconcile", {
        method: "DELETE",
        body: JSON.stringify({ transactionId, paymentId }),
      })
      router.refresh()
    } catch (error) {
      console.error("Error unreconciling:", error)
    } finally {
      setIsReconciling(null)
    }
  }

  const tabs: { key: TabKey; label: string; count: number }[] = [
    { key: "credits",    label: "Incoming (Credits)", count: unreconciledCredits.length },
    { key: "debits",     label: "Outgoing (Debits)",  count: unreconciledDebits.length  },
    { key: "reconciled", label: "Reconciled",          count: reconciledTxns.length      },
  ]

  return (
    <div className="space-y-6">
      {/* Summary row */}
      <div className="grid grid-cols-3 gap-4">
        <div className="rounded-lg border p-4 space-y-1">
          <p className="text-xs text-muted-foreground">Unreconciled Credits</p>
          <p className="text-2xl font-bold text-green-600">{unreconciledCredits.length}</p>
        </div>
        <div className="rounded-lg border p-4 space-y-1">
          <p className="text-xs text-muted-foreground">Unreconciled Debits</p>
          <p className="text-2xl font-bold text-amber-600">{unreconciledDebits.length}</p>
        </div>
        <div className="rounded-lg border p-4 space-y-1">
          <p className="text-xs text-muted-foreground">Reconciled</p>
          <p className="text-2xl font-bold">{reconciledTxns.length}</p>
        </div>
      </div>

      {/* Tab bar */}
      <div className="flex gap-1 border-b">
        {tabs.map((t) => (
          <button
            key={t.key}
            onClick={() => setActiveTab(t.key)}
            className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
              activeTab === t.key
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
          >
            {t.label}
            {t.count > 0 && (
              <span className="ml-2 rounded-full bg-muted px-1.5 py-0.5 text-xs">{t.count}</span>
            )}
          </button>
        ))}
      </div>

      {/* ── Credits tab ───────────────────────────────────────────────── */}
      {activeTab === "credits" && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <ArrowUpCircle className="h-5 w-5 text-green-600" />
              Incoming Money — Match to Invoices
            </CardTitle>
          </CardHeader>
          <CardContent>
            {unreconciledCredits.length === 0 ? (
              <p className="text-sm text-muted-foreground">All credit transactions are reconciled.</p>
            ) : (
              <div className="space-y-4">
                {unreconciledCredits.map((transaction) => {
                  const creditAmt = Number(transaction.credit)
                  const suggested = getSuggestedMatch(creditAmt, payments)
                  const selectedId = selectedPayments[transaction.id] || (suggested?.id ?? "")
                  const isWorking = isReconciling === transaction.id
                  const confidencePct = suggested
                    ? Math.round((1 - Math.abs(Number(suggested.amount) - creditAmt) / creditAmt) * 100)
                    : 0

                  return (
                    <div key={transaction.id} className="flex items-start gap-4 p-4 border rounded-lg">
                      <div className="flex-1 space-y-1 min-w-0">
                        <p className="font-medium truncate">{transaction.description}</p>
                        <div className="flex items-center gap-2 flex-wrap">
                          <p className="text-sm text-muted-foreground">
                            {new Date(transaction.transaction_date).toLocaleDateString("en-IN")}
                          </p>
                          <CategoryBadge
                            transactionId={transaction.id}
                            description={transaction.description || ""}
                            category={transaction.category || "Uncategorized"}
                            source={transaction.category_source ?? undefined}
                          />
                        </div>
                        {transaction.reference_number && (
                          <p className="text-xs text-muted-foreground">Ref: {transaction.reference_number}</p>
                        )}
                        {suggested && (
                          <div className="flex items-center gap-1.5 text-xs text-amber-600 dark:text-amber-400">
                            <Sparkles className="h-3.5 w-3.5" />
                            Auto-match suggestion: <strong>{suggested.invoice?.invoice_number || "Payment"}</strong>
                            <span className="text-muted-foreground">({confidencePct}% match)</span>
                          </div>
                        )}
                      </div>
                      <div className="text-right shrink-0">
                        <p className="text-lg font-bold text-green-600">
                          +₹{creditAmt.toLocaleString("en-IN")}
                        </p>
                      </div>
                      <div className="flex items-center gap-2 shrink-0">
                        <Select
                          value={selectedId}
                          onValueChange={(value) =>
                            setSelectedPayments((prev) => ({ ...prev, [transaction.id]: value }))
                          }
                        >
                          <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder="Select payment" />
                          </SelectTrigger>
                          <SelectContent>
                            {payments.map((payment) => (
                              <SelectItem key={payment.id} value={payment.id}>
                                {payment.invoice?.invoice_number || "Payment"} — ₹
                                {Number(payment.amount).toLocaleString("en-IN")}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <Button
                          size="sm"
                          onClick={() => handleReconcile(transaction.id, selectedId || selectedPayments[transaction.id])}
                          disabled={!(selectedId || selectedPayments[transaction.id]) || isWorking}
                        >
                          {isWorking ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4 mr-1" />}
                          {!isWorking && "Match"}
                        </Button>
                      </div>
                    </div>
                  )
                })}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* ── Debits tab ────────────────────────────────────────────────── */}
      {activeTab === "debits" && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <ArrowDownCircle className="h-5 w-5 text-amber-600" />
              Outgoing Money — Expenses &amp; Payments
            </CardTitle>
          </CardHeader>
          <CardContent>
            {unreconciledDebits.length === 0 ? (
              <p className="text-sm text-muted-foreground">No unreconciled debit transactions.</p>
            ) : (
              <div className="space-y-3">
                {unreconciledDebits.map((transaction) => {
                  const debitAmt = Number(transaction.debit)
                  const isWorking = isReconciling === transaction.id
                  const desc = (transaction.description || "").toLowerCase()
                  const isCCPayment =
                    desc.includes("infinity") || desc.includes("cc payment") || desc.includes("credit card")

                  return (
                    <div key={transaction.id} className="flex items-start gap-4 p-4 border rounded-lg">
                      <div className="flex-1 space-y-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <p className="font-medium truncate">{transaction.description}</p>
                          {isCCPayment && (
                            <Badge variant="outline" className="text-xs shrink-0">CC Payment</Badge>
                          )}
                        </div>
                        <div className="flex items-center gap-2 flex-wrap">
                          <p className="text-sm text-muted-foreground">
                            {new Date(transaction.transaction_date).toLocaleDateString("en-IN")}
                          </p>
                          <CategoryBadge
                            transactionId={transaction.id}
                            description={transaction.description || ""}
                            category={transaction.category || "Uncategorized"}
                            source={transaction.category_source ?? undefined}
                          />
                        </div>
                        {transaction.reference_number && (
                          <p className="text-xs text-muted-foreground">Ref: {transaction.reference_number}</p>
                        )}
                      </div>
                      <div className="text-right shrink-0">
                        <p className="text-lg font-bold text-red-600">
                          −₹{debitAmt.toLocaleString("en-IN")}
                        </p>
                      </div>
                      {/* Debits can still be manually reconciled to a payment record */}
                      <div className="flex items-center gap-2 shrink-0">
                        <Select
                          value={selectedPayments[transaction.id] ?? ""}
                          onValueChange={(value) =>
                            setSelectedPayments((prev) => ({ ...prev, [transaction.id]: value }))
                          }
                        >
                          <SelectTrigger className="w-[180px]">
                            <SelectValue placeholder="Link payment (opt.)" />
                          </SelectTrigger>
                          <SelectContent>
                            {payments.map((payment) => (
                              <SelectItem key={payment.id} value={payment.id}>
                                {payment.invoice?.invoice_number || "Payment"} — ₹
                                {Number(payment.amount).toLocaleString("en-IN")}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <Button
                          size="sm"
                          onClick={() =>
                            handleReconcile(transaction.id, selectedPayments[transaction.id])
                          }
                          disabled={!selectedPayments[transaction.id] || isWorking}
                        >
                          {isWorking ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4 mr-1" />}
                          {!isWorking && "Link"}
                        </Button>
                      </div>
                    </div>
                  )
                })}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* ── Reconciled tab ───────────────────────────────────────────── */}
      {activeTab === "reconciled" && (
        <Card>
          <CardHeader>
            <CardTitle>Reconciled Transactions ({reconciledTxns.length})</CardTitle>
          </CardHeader>
          <CardContent>
            {reconciledTxns.length === 0 ? (
              <p className="text-sm text-muted-foreground">No reconciled transactions yet.</p>
            ) : (
              <div className="space-y-3">
                {reconciledTxns.map((transaction) => {
                  const isCredit = transaction.credit && Number(transaction.credit) > 0
                  const amount = isCredit ? Number(transaction.credit) : Number(transaction.debit)
                  return (
                    <div key={transaction.id} className="flex items-center gap-4 p-4 border rounded-lg bg-muted/30">
                      <div className="flex-1 space-y-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <p className="font-medium truncate">{transaction.description}</p>
                          <Badge className="bg-green-500/10 text-green-700 shrink-0">Reconciled</Badge>
                        </div>
                        <p className="text-sm text-muted-foreground">
                          {new Date(transaction.transaction_date).toLocaleDateString("en-IN")}
                        </p>
                        {transaction.payment?.invoice?.invoice_number && (
                          <p className="text-sm text-muted-foreground">
                            Matched: {transaction.payment.invoice.invoice_number}
                          </p>
                        )}
                      </div>
                      <div className="text-right shrink-0">
                        <p className={`text-lg font-bold ${isCredit ? "text-green-600" : "text-red-600"}`}>
                          {isCredit ? "+" : "−"}₹{amount.toLocaleString("en-IN")}
                        </p>
                      </div>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleUnreconcile(transaction.id, transaction.payment_id)}
                        disabled={isReconciling === transaction.id}
                      >
                        <X className="h-4 w-4 mr-1" />
                        Unmatch
                      </Button>
                    </div>
                  )
                })}
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Unmatched Payments */}
      {payments.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>Unmatched Invoice Payments ({payments.length})</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {payments.map((payment) => (
                <div key={payment.id} className="flex items-center justify-between p-4 border rounded-lg">
                  <div className="space-y-1">
                    <p className="font-medium">{payment.invoice?.invoice_number || "Payment"}</p>
                    <p className="text-sm text-muted-foreground">
                      {new Date(payment.payment_date).toLocaleDateString("en-IN")}
                    </p>
                  </div>
                  <p className="font-bold text-green-600">
                    ₹{Number(payment.amount).toLocaleString("en-IN")}
                  </p>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  )
}

import { sql } from "@/lib/db"
import { getCurrentOrgId } from "@/lib/get-org"
import { NextResponse } from "next/server"
import { Resend } from "resend"

// GET /api/notify/digest
// Called by Vercel Cron daily at 10pm IST (4:30pm UTC).
// Sends a digest email if there are action items.
// Set NOTIFICATION_EMAIL in env to control the recipient.

const CRON_SECRET = process.env.CRON_SECRET

function fmt(n: number) {
  return `₹${Number(n).toLocaleString("en-IN", { maximumFractionDigits: 0 })}`
}

function fmtDate(d: string) {
  return new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })
}

function buildDigestHtml(data: {
  overdueInvoices: Array<{ invoice_number: string; total_amount: number; invoice_date: string; daysOverdue: number }>
  unreconciledCredits: Array<{ description: string; credit: number; transaction_date: string }>
  unreconciledDebits:  Array<{ description: string; debit:  number; transaction_date: string }>
  appUrl: string
}): string {
  const hasItems = data.overdueInvoices.length + data.unreconciledCredits.length + data.unreconciledDebits.length > 0

  if (!hasItems) return ""

  const overdueSection = data.overdueInvoices.length > 0 ? `
    <h2 style="font-size:16px;font-weight:700;margin:24px 0 12px;color:#dc2626">
      Overdue Invoices (${data.overdueInvoices.length})
    </h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead>
        <tr style="background:#fef2f2">
          <th style="text-align:left;padding:8px 12px;color:#666">Invoice</th>
          <th style="text-align:left;padding:8px 12px;color:#666">Date</th>
          <th style="text-align:left;padding:8px 12px;color:#666">Days Overdue</th>
          <th style="text-align:right;padding:8px 12px;color:#666">Amount</th>
        </tr>
      </thead>
      <tbody>
        ${data.overdueInvoices.map((inv) => `
          <tr style="border-top:1px solid #fecaca">
            <td style="padding:8px 12px;font-weight:600">${inv.invoice_number}</td>
            <td style="padding:8px 12px;color:#555">${fmtDate(inv.invoice_date)}</td>
            <td style="padding:8px 12px;color:#dc2626;font-weight:600">${inv.daysOverdue}d</td>
            <td style="padding:8px 12px;text-align:right">${fmt(inv.total_amount)}</td>
          </tr>
        `).join("")}
      </tbody>
    </table>` : ""

  const creditSection = data.unreconciledCredits.length > 0 ? `
    <h2 style="font-size:16px;font-weight:700;margin:24px 0 12px;color:#16a34a">
      Unreconciled Credits (${data.unreconciledCredits.length})
    </h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead>
        <tr style="background:#f0fdf4">
          <th style="text-align:left;padding:8px 12px;color:#666">Description</th>
          <th style="text-align:left;padding:8px 12px;color:#666">Date</th>
          <th style="text-align:right;padding:8px 12px;color:#666">Amount</th>
        </tr>
      </thead>
      <tbody>
        ${data.unreconciledCredits.map((tx) => `
          <tr style="border-top:1px solid #bbf7d0">
            <td style="padding:8px 12px;font-weight:600">${tx.description}</td>
            <td style="padding:8px 12px;color:#555">${fmtDate(tx.transaction_date)}</td>
            <td style="padding:8px 12px;text-align:right;color:#16a34a;font-weight:600">+${fmt(tx.credit)}</td>
          </tr>
        `).join("")}
      </tbody>
    </table>` : ""

  const debitSection = data.unreconciledDebits.length > 0 ? `
    <h2 style="font-size:16px;font-weight:700;margin:24px 0 12px;color:#d97706">
      Unreconciled Debits (${data.unreconciledDebits.length})
    </h2>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead>
        <tr style="background:#fffbeb">
          <th style="text-align:left;padding:8px 12px;color:#666">Description</th>
          <th style="text-align:left;padding:8px 12px;color:#666">Date</th>
          <th style="text-align:right;padding:8px 12px;color:#666">Amount</th>
        </tr>
      </thead>
      <tbody>
        ${data.unreconciledDebits.map((tx) => `
          <tr style="border-top:1px solid #fde68a">
            <td style="padding:8px 12px;font-weight:600">${tx.description}</td>
            <td style="padding:8px 12px;color:#555">${fmtDate(tx.transaction_date)}</td>
            <td style="padding:8px 12px;text-align:right;color:#d97706;font-weight:600">−${fmt(tx.debit)}</td>
          </tr>
        `).join("")}
      </tbody>
    </table>` : ""

  return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8" /><meta name="viewport" content="width=device-width, initial-scale=1" /></head>
<body style="font-family:'Segoe UI',Arial,sans-serif;background:#f4f4f5;margin:0;padding:0">
  <div style="max-width:640px;margin:0 auto;background:#fff">
    <div style="background:#1a1a2e;padding:24px 32px">
      <h1 style="color:#fff;margin:0;font-size:20px;font-weight:700">InvoiceFlow Daily Digest</h1>
      <p style="color:#a3a3cc;margin:4px 0 0;font-size:13px">${new Date().toLocaleDateString("en-IN", { weekday:"long", day:"2-digit", month:"long", year:"numeric" })}</p>
    </div>
    <div style="padding:24px 32px">
      ${overdueSection}
      ${creditSection}
      ${debitSection}
      <div style="margin-top:28px">
        <a href="${data.appUrl}/dashboard/reconciliation"
           style="display:inline-block;background:#1a1a2e;color:#fff;text-decoration:none;padding:12px 24px;border-radius:6px;font-size:14px;font-weight:600">
          Open Reconciliation →
        </a>
      </div>
    </div>
    <div style="background:#f4f4f5;padding:16px 32px;font-size:11px;color:#888;text-align:center">
      This is an automated digest from InvoiceFlow. To stop receiving these, remove the Vercel Cron.
    </div>
  </div>
</body>
</html>`
}

export async function GET(request: Request) {
  // Validate cron secret in production (optional but recommended)
  if (CRON_SECRET) {
    const authHeader = request.headers.get("authorization")
    if (authHeader !== `Bearer ${CRON_SECRET}`) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }
  }

  const resendKey = process.env.RESEND_API_KEY
  const toEmail   = process.env.NOTIFICATION_EMAIL

  if (!resendKey || !toEmail) {
    return NextResponse.json(
      { error: "RESEND_API_KEY and NOTIFICATION_EMAIL must be set to send digest emails" },
      { status: 500 },
    )
  }

  try {
    const orgId = await getCurrentOrgId()

    // Overdue invoices (past due date, still unpaid)
    const overdueRows = await sql`
      SELECT id, invoice_number, total_amount, invoice_date, payment_due_days
      FROM invoices
      WHERE org_id = ${orgId}
        AND status IN ('unpaid', 'overdue')
        AND invoice_date + (payment_due_days || ' days')::INTERVAL < NOW()
      ORDER BY invoice_date ASC
    `

    // Unreconciled credits older than 7 days
    const unreconciledCreditRows = await sql`
      SELECT id, description, credit, transaction_date
      FROM bank_transactions
      WHERE org_id = ${orgId}
        AND reconciled = false
        AND credit IS NOT NULL AND credit > 0
        AND created_at < NOW() - INTERVAL '7 days'
      ORDER BY transaction_date DESC
      LIMIT 20
    `

    // Unreconciled debits older than 3 days (potential CC payments not linked)
    const unreconciledDebitRows = await sql`
      SELECT id, description, debit, transaction_date
      FROM bank_transactions
      WHERE org_id = ${orgId}
        AND reconciled = false
        AND debit IS NOT NULL AND debit > 0
        AND (
          LOWER(description) LIKE '%infinity%'
          OR LOWER(description) LIKE '%cc payment%'
          OR LOWER(description) LIKE '%credit card%'
        )
        AND created_at < NOW() - INTERVAL '3 days'
      ORDER BY transaction_date DESC
      LIMIT 20
    `

    const today = new Date()
    const overdueInvoices = overdueRows.map((inv) => {
      const dueDate = new Date(inv.invoice_date as string)
      dueDate.setDate(dueDate.getDate() + (inv.payment_due_days as number))
      const daysOverdue = Math.floor((today.getTime() - dueDate.getTime()) / (1000 * 60 * 60 * 24))
      return { ...inv, daysOverdue: Math.max(0, daysOverdue) }
    }) as Array<{ invoice_number: string; total_amount: number; invoice_date: string; daysOverdue: number }>

    const totalActionItems = overdueInvoices.length + unreconciledCreditRows.length + unreconciledDebitRows.length

    if (totalActionItems === 0) {
      return NextResponse.json({ sent: false, reason: "No action items — digest skipped" })
    }

    const appUrl = process.env.NEXT_PUBLIC_APP_URL || "https://localhost:3000"

    const html = buildDigestHtml({
      overdueInvoices,
      unreconciledCredits: unreconciledCreditRows as Array<{ description: string; credit: number; transaction_date: string }>,
      unreconciledDebits:  unreconciledDebitRows  as Array<{ description: string; debit:  number; transaction_date: string }>,
      appUrl,
    })

    const resend = new Resend(resendKey)
    const { data, error } = await resend.emails.send({
      from: "InvoiceFlow <digest@resend.dev>",
      to: [toEmail],
      subject: `Finance Digest — ${totalActionItems} item${totalActionItems > 1 ? "s" : ""} need attention`,
      html,
    })

    if (error) throw new Error(error.message)

    return NextResponse.json({ sent: true, emailId: data?.id, actionItems: totalActionItems })
  } catch (error) {
    console.error("[notify/digest] Error:", error)
    return NextResponse.json(
      { error: error instanceof Error ? error.message : "Digest failed" },
      { status: 500 },
    )
  }
}

{
