"use client"

import type React from "react"
import { useState, useCallback } from "react"
import { useRouter } from "next/navigation"
import { fetchFromAPI } from "@/lib/fetch"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Plus, Trash2, AlertCircle } from "lucide-react"
import type { Client, Profile, InvoiceLineItem } from "@/lib/types"

// Standard Indian GST rate combos — (combined%, CGST%, SGST%)
const GST_OPTIONS = [
  { label: "0% GST",  combined: 0,  half: 0 },
  { label: "5% GST",  combined: 5,  half: 2.5 },
  { label: "12% GST", combined: 12, half: 6 },
  { label: "18% GST", combined: 18, half: 9 },
  { label: "28% GST", combined: 28, half: 14 },
]

interface LineItemRow {
  description: string
  hsn_code: string
  quantity: string
  rate: string
  gst_combined: number   // 0 | 5 | 12 | 18 | 28
}

function emptyRow(): LineItemRow {
  return { description: "", hsn_code: "998314", quantity: "1", rate: "", gst_combined: 18 }
}

function computeRow(row: LineItemRow): InvoiceLineItem {
  const qty  = parseFloat(row.quantity) || 1
  const rate = parseFloat(row.rate)     || 0
  const gst  = GST_OPTIONS.find((o) => o.combined === row.gst_combined) ?? GST_OPTIONS[3]
  const amount    = Math.round(qty * rate * 100) / 100
  const cgstAmt   = Math.round(amount * (gst.half / 100) * 100) / 100
  const sgstAmt   = cgstAmt
  return {
    description: row.description,
    hsn_code:    row.hsn_code || null,
    quantity:    qty,
    rate,
    cgst_rate:   gst.half,
    sgst_rate:   gst.half,
    cgst_amount: cgstAmt,
    sgst_amount: sgstAmt,
    amount,
  }
}

interface InvoiceFormProps {
  clients: Client[]
  profile: Profile | null
  initialData?: {
    line_items?: InvoiceLineItem[]
    [key: string]: unknown
  }
}

export function InvoiceForm({ clients, profile }: InvoiceFormProps) {
  const router = useRouter()
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError]   = useState<string | null>(null)

  const [header, setHeader] = useState({
    client_id:        "",
    invoice_number:   "",
    invoice_date:     new Date().toISOString().split("T")[0],
    service_date:     new Date().toISOString().split("T")[0],
    payment_due_days: "30",
    terms: "Payment due within the agreed terms. All design documents remain the exclusive property of the designer until payment is received in full.",
  })

  const [rows, setRows] = useState<LineItemRow[]>([emptyRow()])

  const updateHeader = (field: string, value: string) =>
    setHeader((prev) => ({ ...prev, [field]: value }))

  const updateRow = useCallback((index: number, field: keyof LineItemRow, value: string | number) => {
    setRows((prev) => prev.map((r, i) => i === index ? { ...r, [field]: value } : r))
  }, [])

  const addRow = () => setRows((prev) => [...prev, emptyRow()])

  const removeRow = (index: number) =>
    setRows((prev) => prev.length > 1 ? prev.filter((_, i) => i !== index) : prev)

  // Computed totals
  const computed = rows.map(computeRow)
  const subtotal    = computed.reduce((s, r) => s + r.amount, 0)
  const totalCgst   = computed.reduce((s, r) => s + r.cgst_amount, 0)
  const totalSgst   = computed.reduce((s, r) => s + r.sgst_amount, 0)
  const grandTotal  = subtotal + totalCgst + totalSgst

  const fmt = (n: number) =>
    n.toLocaleString("en-IN", { minimumFractionDigits: 2, maximumFractionDigits: 2 })

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!header.client_id)  { setError("Please select a client"); return }
    if (!header.invoice_number) { setError("Invoice number is required"); return }
    if (rows.some((r) => !r.description || !r.rate)) {
      setError("Each line item needs a description and rate"); return
    }

    setIsLoading(true)
    setError(null)

    try {
      const line_items = computed

      const result = await fetchFromAPI("/api/invoices", {
        method: "POST",
        body: JSON.stringify({
          client_id:        Number(header.client_id),
          invoice_number:   header.invoice_number,
          invoice_date:     header.invoice_date,
          service_date:     header.service_date || null,
          description:      rows[0].description, // fallback for legacy display
          terms:            header.terms || null,
          status:           "unpaid",
          payment_due_days: Number(header.payment_due_days),
          line_items,
          // header-level totals (also sent for backwards compat)
          amount_before_tax: subtotal,
          cgst_rate: computed[0]?.cgst_rate ?? 9,
          sgst_rate: computed[0]?.sgst_rate ?? 9,
          cgst_amount: totalCgst,
          sgst_amount: totalSgst,
          total_amount: grandTotal,
        }),
      })

      router.push(`/dashboard/invoices/${result.id}`)
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to create invoice")
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {/* ── Header ──────────────────────────────────────────── */}
      <Card>
        <CardHeader><CardTitle>Invoice Details</CardTitle></CardHeader>
        <CardContent className="grid gap-4 sm:grid-cols-2">
          {/* Client */}
          <div className="space-y-1.5">
            <Label htmlFor="client">Client *</Label>
            <Select value={header.client_id} onValueChange={(v) => updateHeader("client_id", v)}>
              <SelectTrigger id="client">
                <SelectValue placeholder="Select client" />
              </SelectTrigger>
              <SelectContent>
                {clients.map((c) => (
                  <SelectItem key={c.id} value={String(c.id)}>{c.name}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Invoice number */}
          <div className="space-y-1.5">
            <Label htmlFor="invoice_number">Invoice Number *</Label>
            <Input
              id="invoice_number"
              value={header.invoice_number}
              onChange={(e) => updateHeader("invoice_number", e.target.value)}
              placeholder="INV-001"
              required
            />
          </div>

          {/* Invoice date */}
          <div className="space-y-1.5">
            <Label htmlFor="invoice_date">Invoice Date</Label>
            <Input
              id="invoice_date"
              type="date"
              value={header.invoice_date}
              onChange={(e) => updateHeader("invoice_date", e.target.value)}
            />
          </div>

          {/* Service date */}
          <div className="space-y-1.5">
            <Label htmlFor="service_date">Service Date</Label>
            <Input
              id="service_date"
              type="date"
              value={header.service_date}
              onChange={(e) => updateHeader("service_date", e.target.value)}
            />
          </div>

          {/* Payment due */}
          <div className="space-y-1.5">
            <Label htmlFor="payment_due_days">Payment Due (Days)</Label>
            <Input
              id="payment_due_days"
              type="number"
              min="0"
              value={header.payment_due_days}
              onChange={(e) => updateHeader("payment_due_days", e.target.value)}
            />
          </div>
        </CardContent>
      </Card>

      {/* ── Line Items Table ─────────────────────────────────── */}
      <Card>
        <CardHeader>
          <CardTitle>Line Items</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          {/* Column headers */}
          <div className="hidden sm:grid grid-cols-[2fr_0.8fr_0.8fr_1fr_0.8fr_0.8fr_auto] gap-2 text-xs font-medium text-muted-foreground px-1">
            <span>Description *</span>
            <span>HSN/SAC</span>
            <span>Qty</span>
            <span>Rate (₹) *</span>
            <span>GST</span>
            <span className="text-right">Amount (₹)</span>
            <span />
          </div>

          {rows.map((row, i) => {
            const c = computeRow(row)
            const lineTotal = c.amount + c.cgst_amount + c.sgst_amount
            return (
              <div
                key={i}
                className="grid grid-cols-1 sm:grid-cols-[2fr_0.8fr_0.8fr_1fr_0.8fr_0.8fr_auto] gap-2 items-start border rounded-lg p-3 sm:p-2 sm:border-0 sm:rounded-none sm:px-1"
              >
                {/* Description */}
                <div>
                  <Label className="sm:hidden text-xs mb-1 block">Description *</Label>
                  <Textarea
                    value={row.description}
                    onChange={(e) => updateRow(i, "description", e.target.value)}
                    placeholder="Service description"
                    className="min-h-[60px] text-sm resize-y"
                    required
                  />
                </div>

                {/* HSN */}
                <div>
                  <Label className="sm:hidden text-xs mb-1 block">HSN/SAC</Label>
                  <Input
                    value={row.hsn_code}
                    onChange={(e) => updateRow(i, "hsn_code", e.target.value)}
                    placeholder="998314"
                    className="text-sm"
                  />
                </div>

                {/* Qty */}
                <div>
                  <Label className="sm:hidden text-xs mb-1 block">Qty</Label>
                  <Input
                    type="number"
                    min="0.001"
                    step="0.001"
                    value={row.quantity}
                    onChange={(e) => updateRow(i, "quantity", e.target.value)}
                    className="text-sm"
                  />
                </div>

                {/* Rate */}
                <div>
                  <Label className="sm:hidden text-xs mb-1 block">Rate (₹) *</Label>
                  <Input
                    type="number"
                    min="0"
                    step="0.01"
                    value={row.rate}
                    onChange={(e) => updateRow(i, "rate", e.target.value)}
                    placeholder="0.00"
                    className="text-sm"
                    required
                  />
                </div>

                {/* GST */}
                <div>
                  <Label className="sm:hidden text-xs mb-1 block">GST</Label>
                  <Select
                    value={String(row.gst_combined)}
                    onValueChange={(v) => updateRow(i, "gst_combined", Number(v))}
                  >
                    <SelectTrigger className="text-sm">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {GST_OPTIONS.map((o) => (
                        <SelectItem key={o.combined} value={String(o.combined)}>
                          {o.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                {/* Line total */}
                <div className="flex items-center justify-end">
                  <span className="text-sm font-medium tabular-nums">
                    {fmt(lineTotal)}
                  </span>
                </div>

                {/* Remove */}
                <div className="flex items-center justify-end">
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8 text-muted-foreground hover:text-destructive"
                    onClick={() => removeRow(i)}
                    disabled={rows.length === 1}
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            )
          })}

          <Button type="button" variant="outline" size="sm" onClick={addRow} className="mt-1">
            <Plus className="h-4 w-4 mr-1.5" />
            Add Line Item
          </Button>
        </CardContent>
      </Card>

      {/* ── Totals + Terms ───────────────────────────────────── */}
      <div className="grid gap-6 lg:grid-cols-2">
        {/* Terms */}
        <Card>
          <CardHeader><CardTitle>Terms &amp; Conditions</CardTitle></CardHeader>
          <CardContent>
            <Textarea
              value={header.terms}
              onChange={(e) => updateHeader("terms", e.target.value)}
              className="min-h-[120px] resize-y text-sm"
              placeholder="Payment terms…"
            />
          </CardContent>
        </Card>

        {/* Summary */}
        <Card>
          <CardHeader><CardTitle>Summary</CardTitle></CardHeader>
          <CardContent className="space-y-2 text-sm">
            <div className="flex justify-between">
              <span className="text-muted-foreground">Subtotal</span>
              <span className="font-medium tabular-nums">₹{fmt(subtotal)}</span>
            </div>
            {/* Per-row GST breakdown if rates differ */}
            {[...new Set(rows.map((r) => r.gst_combined))].map((rate) => {
              const gst = GST_OPTIONS.find((o) => o.combined === rate)!
              const rowsAtRate = computed.filter((_, i) => rows[i].gst_combined === rate)
              const cgstHere = rowsAtRate.reduce((s, r) => s + r.cgst_amount, 0)
              const sgstHere = rowsAtRate.reduce((s, r) => s + r.sgst_amount, 0)
              if (cgstHere === 0 && sgstHere === 0) return null
              return (
                <div key={rate}>
                  <div className="flex justify-between text-muted-foreground">
                    <span>CGST @ {gst.half}%</span>
                    <span className="tabular-nums">₹{fmt(cgstHere)}</span>
                  </div>
                  <div className="flex justify-between text-muted-foreground">
                    <span>SGST @ {gst.half}%</span>
                    <span className="tabular-nums">₹{fmt(sgstHere)}</span>
                  </div>
                </div>
              )
            })}
            <div className="flex justify-between border-t pt-2 font-bold text-base">
              <span>Grand Total</span>
              <span className="tabular-nums">₹{fmt(grandTotal)}</span>
            </div>

            {error && (
              <div className="flex items-start gap-2 text-sm text-destructive pt-2">
                <AlertCircle className="h-4 w-4 mt-0.5 shrink-0" />
                <span>{error}</span>
              </div>
            )}

            <Button type="submit" className="w-full mt-4" disabled={isLoading}>
              {isLoading ? "Creating…" : "Create Invoice"}
            </Button>
          </CardContent>
        </Card>
      </div>
    </form>
  )
}

import { type NextRequest, NextResponse } from "next/server"
import { generateText } from "ai"
import { createGoogleGenerativeAI } from "@ai-sdk/google"

// POST /api/invoices/ocr
// Accepts a multipart form with a "file" field (PNG/JPG/WEBP/PDF).
// Returns extracted invoice data as JSON for the user to confirm.
//
// Requires env: GOOGLE_GENERATIVE_AI_API_KEY
// (Google Gemini — free tier: 1500 req/day, ~$0.0001/image on paid)

const PROMPT = `You are an invoice data extractor for Indian tax invoices.
Extract all invoice fields from this document and return ONLY a valid JSON object — no markdown, no explanation.

Return this exact shape:
{
  "invoice_number": string | null,
  "client_name": string | null,
  "client_gstin": string | null,
  "invoice_date": "YYYY-MM-DD" | null,
  "line_items": [
    {
      "description": string,
      "hsn_code": string | null,
      "quantity": number,
      "rate": number,
      "gst_rate": number (combined %, e.g. 18 for 9+9)
    }
  ],
  "cgst_rate": number | null,
  "sgst_rate": number | null,
  "total_amount": number | null,
  "terms": string | null
}

Rules:
- If you cannot read a field clearly, set it to null.
- For line_items, include every line on the invoice.
- gst_rate should be the combined rate (CGST + SGST), e.g. 18 for 9% + 9%.
- Amounts should be plain numbers without currency symbols or commas.
- invoice_date must be YYYY-MM-DD format.`

export async function POST(request: NextRequest) {
  const apiKey = process.env.GOOGLE_GENERATIVE_AI_API_KEY

  if (!apiKey) {
    return NextResponse.json(
      {
        error: "OCR not configured",
        detail: "Add GOOGLE_GENERATIVE_AI_API_KEY to your environment variables. Get a free key at aistudio.google.com.",
      },
      { status: 503 },
    )
  }

  try {
    const formData = await request.formData()
    const file = formData.get("file") as File | null

    if (!file) {
      return NextResponse.json({ error: "No file provided" }, { status: 400 })
    }

    const ext = file.name.split(".").pop()?.toLowerCase() ?? ""
    const supported = ["png", "jpg", "jpeg", "webp", "pdf"]
    if (!supported.includes(ext)) {
      return NextResponse.json(
        { error: `Unsupported file type ".${ext}". Use PNG, JPG, WEBP, or PDF.` },
        { status: 400 },
      )
    }

    const arrayBuffer = await file.arrayBuffer()
    const buffer = Buffer.from(arrayBuffer)

    const google = createGoogleGenerativeAI({ apiKey })

    let result: string

    if (ext === "pdf") {
      // For PDFs, extract text first then ask Gemini to structure it
      const pdfParse = (await import("pdf-parse")).default
      const pdfData = await pdfParse(buffer)
      const text = pdfData.text?.trim()

      if (!text) {
        return NextResponse.json(
          { error: "Could not extract text from PDF. Is it a scanned/image PDF? Try uploading as an image instead." },
          { status: 422 },
        )
      }

      const { text: response } = await generateText({
        model: google("gemini-2.0-flash"),
        messages: [
          {
            role: "user",
            content: `${PROMPT}\n\nHere is the invoice text:\n\n${text.slice(0, 8000)}`,
          },
        ],
      })
      result = response
    } else {
      // Image — pass directly as base64
      const base64 = buffer.toString("base64")
      const mimeMap: Record<string, string> = {
        png: "image/png", jpg: "image/jpeg", jpeg: "image/jpeg", webp: "image/webp",
      }
      const mimeType = mimeMap[ext] ?? "image/jpeg"

      const { text: response } = await generateText({
        model: google("gemini-2.0-flash"),
        messages: [
          {
            role: "user",
            content: [
              { type: "image", image: base64, mimeType },
              { type: "text", text: PROMPT },
            ],
          },
        ],
      })
      result = response
    }

    // Strip markdown code fences if Gemini wraps the JSON
    const cleaned = result.replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/i, "").trim()

    let parsed: Record<string, unknown>
    try {
      parsed = JSON.parse(cleaned)
    } catch {
      return NextResponse.json(
        { error: "AI returned unexpected output. Try a clearer image.", raw: result.slice(0, 500) },
        { status: 422 },
      )
    }

    return NextResponse.json({ success: true, data: parsed })
  } catch (error) {
    console.error("[invoices/ocr] Error:", error)
    return NextResponse.json(
      { error: error instanceof Error ? error.message : "OCR failed" },
      { status: 500 },
    )
  }
}

"use client"

import type React from "react"
import { useState } from "react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription, SheetTrigger,
} from "@/components/ui/sheet"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import {
  Upload, Download, FileText, CheckCircle2, AlertCircle, Loader2,
  Image as ImageIcon, FileSearch, Pencil,
} from "lucide-react"
import { useRouter } from "next/navigation"

// ── GST options ───────────────────────────────────────────
const GST_OPTIONS = [0, 5, 12, 18, 28]

// ── Types ─────────────────────────────────────────────────
interface ImportResult {
  inserted: number; skipped: number; total: number
  parseErrors?: Array<{ line: number; message: string }>
}

interface OcrLineItem {
  description: string; hsn_code: string | null; quantity: number; rate: number; gst_rate: number
}

interface OcrData {
  invoice_number: string | null; client_name: string | null; client_gstin: string | null
  invoice_date: string | null; line_items: OcrLineItem[]
  cgst_rate: number | null; sgst_rate: number | null; total_amount: number | null; terms: string | null
}

type TabKey = "csv" | "image"

// ── Main component ────────────────────────────────────────
export function InvoiceImportModal() {
  const router = useRouter()
  const [open, setOpen] = useState(false)
  const [tab, setTab] = useState<TabKey>("csv")

  // CSV state
  const [csvFile, setCsvFile] = useState<File | null>(null)
  const [csvUploading, setCsvUploading] = useState(false)
  const [csvError, setCsvError] = useState<string | null>(null)
  const [csvResult, setCsvResult] = useState<ImportResult | null>(null)

  // OCR state
  const [ocrFile, setOcrFile] = useState<File | null>(null)
  const [ocrScanning, setOcrScanning] = useState(false)
  const [ocrError, setOcrError] = useState<string | null>(null)
  const [ocrData, setOcrData] = useState<OcrData | null>(null)
  const [ocrSaving, setOcrSaving] = useState(false)
  const [ocrSaved, setOcrSaved] = useState(false)

  const handleOpenChange = (next: boolean) => {
    setOpen(next)
    if (!next) {
      setCsvFile(null); setCsvError(null); setCsvResult(null)
      setOcrFile(null); setOcrError(null); setOcrData(null); setOcrSaved(false)
    }
  }

  // ── CSV import ──────────────────────────────────────────
  const handleCsvImport = async () => {
    if (!csvFile) { setCsvError("Please select a CSV file"); return }
    setCsvUploading(true); setCsvError(null)
    try {
      const fd = new FormData(); fd.append("file", csvFile)
      const res = await fetch("/api/invoices/import", { method: "POST", body: fd })
      const json = await res.json()
      if (!res.ok) { setCsvError(json.error ?? "Import failed"); return }
      setCsvResult(json); setCsvFile(null)
      router.refresh()
    } catch (err) {
      setCsvError(err instanceof Error ? err.message : "Import failed")
    } finally {
      setCsvUploading(false)
    }
  }

  // ── OCR scan ────────────────────────────────────────────
  const handleOcrScan = async () => {
    if (!ocrFile) { setOcrError("Please select a file"); return }
    setOcrScanning(true); setOcrError(null); setOcrData(null)
    try {
      const fd = new FormData(); fd.append("file", ocrFile)
      const res = await fetch("/api/invoices/ocr", { method: "POST", body: fd })
      const json = await res.json()
      if (!res.ok) { setOcrError(json.detail || json.error || "Scan failed"); return }
      setOcrData(json.data as OcrData)
    } catch (err) {
      setOcrError(err instanceof Error ? err.message : "Scan failed")
    } finally {
      setOcrScanning(false)
    }
  }

  // ── Save OCR'd invoice ──────────────────────────────────
  const handleOcrSave = async () => {
    if (!ocrData) return
    setOcrSaving(true); setOcrError(null)
    try {
      // Compute line item financials
      const lineItems = (ocrData.line_items ?? []).map((item) => {
        const half = (item.gst_rate ?? 18) / 2
        const amt  = Math.round((item.quantity ?? 1) * (item.rate ?? 0) * 100) / 100
        const cgst = Math.round(amt * (half / 100) * 100) / 100
        return {
          description: item.description,
          hsn_code: item.hsn_code ?? null,
          quantity: item.quantity ?? 1,
          rate: item.rate ?? 0,
          cgst_rate: half, sgst_rate: half,
          cgst_amount: cgst, sgst_amount: cgst,
          amount: amt,
        }
      })

      const subtotal = lineItems.reduce((s, r) => s + r.amount, 0)
      const cgstTotal = lineItems.reduce((s, r) => s + r.cgst_amount, 0)
      const sgstTotal = lineItems.reduce((s, r) => s + r.sgst_amount, 0)

      const res = await fetch("/api/invoices", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          invoice_number:   ocrData.invoice_number ?? `OCR-${Date.now()}`,
          client_id:        1, // placeholder — user should link after saving
          invoice_date:     ocrData.invoice_date ?? new Date().toISOString().split("T")[0],
          description:      lineItems[0]?.description ?? "Imported invoice",
          terms:            ocrData.terms ?? null,
          status:           "unpaid",
          payment_due_days: 30,
          line_items:       lineItems,
          amount_before_tax: subtotal,
          cgst_rate:  lineItems[0]?.cgst_rate ?? 9,
          sgst_rate:  lineItems[0]?.sgst_rate ?? 9,
          cgst_amount: cgstTotal, sgst_amount: sgstTotal,
          total_amount: subtotal + cgstTotal + sgstTotal,
        }),
      })
      const json = await res.json()
      if (!res.ok) { setOcrError(json.error ?? "Save failed"); return }
      setOcrSaved(true)
      router.refresh()
    } catch (err) {
      setOcrError(err instanceof Error ? err.message : "Save failed")
    } finally {
      setOcrSaving(false)
    }
  }

  const updateOcrField = (field: keyof OcrData, value: unknown) =>
    setOcrData((prev) => prev ? { ...prev, [field]: value } : prev)

  const updateOcrLineItem = (i: number, field: keyof OcrLineItem, value: unknown) =>
    setOcrData((prev) => {
      if (!prev) return prev
      const items = [...prev.line_items]
      items[i] = { ...items[i], [field]: value }
      return { ...prev, line_items: items }
    })

  return (
    <Sheet open={open} onOpenChange={handleOpenChange}>
      <SheetTrigger asChild>
        <Button variant="outline">
          <Upload className="h-4 w-4 mr-2" />Import Invoices
        </Button>
      </SheetTrigger>

      <SheetContent side="right" className="w-full sm:max-w-xl overflow-y-auto">
        <SheetHeader>
          <SheetTitle>Import Invoices</SheetTitle>
          <SheetDescription>Upload a CSV file or scan a photo / PDF using AI.</SheetDescription>
        </SheetHeader>

        {/* ── Tabs ── */}
        <div className="flex gap-1 border-b mx-4 my-4">
          {(["csv", "image"] as TabKey[]).map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                tab === t ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"
              }`}
            >
              {t === "csv" ? "CSV Bulk Import" : "Image / PDF (AI)"}
            </button>
          ))}
        </div>

        {/* ── CSV Tab ── */}
        {tab === "csv" && (
          <div className="space-y-4 px-4">
            <div className="rounded-lg border p-4 space-y-2">
              <p className="text-sm font-medium">Step 1 — Download the template</p>
              <Button variant="outline" size="sm" onClick={() => window.open("/api/invoices/import", "_blank")}>
                <Download className="h-4 w-4 mr-2" />Download CSV Template
              </Button>
            </div>

            <div className="rounded-lg border p-4 space-y-3">
              <p className="text-sm font-medium">Step 2 — Upload filled CSV</p>
              <label htmlFor="csv-import-file" className="flex items-center gap-3 cursor-pointer border rounded-md px-4 py-3 hover:bg-muted/40">
                <FileText className="h-5 w-5 text-muted-foreground shrink-0" />
                <span className="text-sm truncate">{csvFile ? csvFile.name : "Choose CSV file…"}</span>
                <input id="csv-import-file" type="file" accept=".csv"
                  onChange={(e) => { setCsvFile(e.target.files?.[0] ?? null); setCsvError(null); setCsvResult(null) }}
                  className="hidden" disabled={csvUploading} />
              </label>
              {csvError && <p className="flex items-center gap-1.5 text-sm text-destructive"><AlertCircle className="h-4 w-4 shrink-0" />{csvError}</p>}
              {csvResult && (
                <div className="text-sm space-y-0.5">
                  <p className="flex items-center gap-1.5 text-green-700 dark:text-green-400 font-medium"><CheckCircle2 className="h-4 w-4" />Import complete</p>
                  <p className="text-muted-foreground">{csvResult.inserted} imported · {csvResult.skipped} skipped</p>
                </div>
              )}
            </div>

            <Button onClick={handleCsvImport} disabled={!csvFile || csvUploading || !!csvResult} className="w-full">
              {csvUploading ? <><Loader2 className="h-4 w-4 mr-2 animate-spin" />Importing…</> : <><Upload className="h-4 w-4 mr-2" />Import</>}
            </Button>

            <details className="text-xs text-muted-foreground">
              <summary className="cursor-pointer font-medium">Column reference</summary>
              <div className="mt-2 space-y-1 pl-2">
                <p><strong className="text-foreground">invoice_number</strong> — required</p>
                <p><strong className="text-foreground">client_name</strong> — required, auto-created if new</p>
                <p><strong className="text-foreground">invoice_date</strong> — DD/MM/YYYY or YYYY-MM-DD</p>
                <p><strong className="text-foreground">amount_before_tax</strong> — numeric only</p>
                <p><strong className="text-foreground">cgst_rate / sgst_rate</strong> — default 9</p>
                <p><strong className="text-foreground">status</strong> — paid / unpaid / overdue</p>
              </div>
            </details>
          </div>
        )}

        {/* ── Image / PDF Tab ── */}
        {tab === "image" && (
          <div className="space-y-4 px-4">
            {!ocrData && !ocrSaved && (
              <>
                <div className="rounded-lg border-2 border-dashed p-6 space-y-3 text-center">
                  <ImageIcon className="h-10 w-10 mx-auto text-muted-foreground" />
                  <div>
                    <p className="text-sm font-medium">Drop your invoice image or PDF</p>
                    <p className="text-xs text-muted-foreground mt-1">PNG · JPG · WEBP · PDF (text-based)</p>
                  </div>
                  <label htmlFor="ocr-file" className="cursor-pointer">
                    <span className="text-sm text-primary underline">{ocrFile ? ocrFile.name : "Choose file"}</span>
                    <input id="ocr-file" type="file" accept=".png,.jpg,.jpeg,.webp,.pdf"
                      onChange={(e) => { setOcrFile(e.target.files?.[0] ?? null); setOcrError(null) }}
                      className="hidden" />
                  </label>
                </div>

                {ocrError && <p className="flex items-center gap-1.5 text-sm text-destructive"><AlertCircle className="h-4 w-4 shrink-0" />{ocrError}</p>}

                <Button onClick={handleOcrScan} disabled={!ocrFile || ocrScanning} className="w-full">
                  {ocrScanning
                    ? <><Loader2 className="h-4 w-4 mr-2 animate-spin" />Scanning with AI…</>
                    : <><FileSearch className="h-4 w-4 mr-2" />Scan with AI</>}
                </Button>
                <p className="text-xs text-center text-muted-foreground">
                  Uses Gemini 2.0 Flash — requires <code className="bg-muted px-1 rounded">GOOGLE_GENERATIVE_AI_API_KEY</code>
                </p>
              </>
            )}

            {ocrSaved && (
              <div className="text-center space-y-3 py-6">
                <CheckCircle2 className="h-10 w-10 mx-auto text-green-500" />
                <p className="font-medium">Invoice saved!</p>
                <p className="text-sm text-muted-foreground">Review and update the client link on the invoice page.</p>
                <Button variant="outline" onClick={() => { setOcrFile(null); setOcrData(null); setOcrSaved(false) }}>Scan Another</Button>
              </div>
            )}

            {ocrData && !ocrSaved && (
              <div className="space-y-4">
                <div className="flex items-center gap-2 text-sm font-medium text-amber-600 dark:text-amber-400">
                  <Pencil className="h-4 w-4" />Review extracted data — edit anything before saving
                </div>

                {/* Header fields */}
                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1">
                    <Label className="text-xs">Invoice Number</Label>
                    <Input value={ocrData.invoice_number ?? ""} onChange={(e) => updateOcrField("invoice_number", e.target.value)} className="text-sm" />
                  </div>
                  <div className="space-y-1">
                    <Label className="text-xs">Invoice Date</Label>
                    <Input type="date" value={ocrData.invoice_date ?? ""} onChange={(e) => updateOcrField("invoice_date", e.target.value)} className="text-sm" />
                  </div>
                  <div className="space-y-1 col-span-2">
                    <Label className="text-xs">Client Name</Label>
                    <Input value={ocrData.client_name ?? ""} onChange={(e) => updateOcrField("client_name", e.target.value)} className="text-sm" />
                  </div>
                </div>

                {/* Line items */}
                <div className="space-y-2">
                  <p className="text-xs font-medium text-muted-foreground">Line Items</p>
                  {(ocrData.line_items ?? []).map((item, i) => (
                    <div key={i} className="border rounded-lg p-3 space-y-2 text-sm">
                      <Input value={item.description} onChange={(e) => updateOcrLineItem(i, "description", e.target.value)} placeholder="Description" />
                      <div className="grid grid-cols-3 gap-2">
                        <div>
                          <Label className="text-xs">Qty</Label>
                          <Input type="number" value={item.quantity} onChange={(e) => updateOcrLineItem(i, "quantity", parseFloat(e.target.value))} className="text-xs" />
                        </div>
                        <div>
                          <Label className="text-xs">Rate (₹)</Label>
                          <Input type="number" value={item.rate} onChange={(e) => updateOcrLineItem(i, "rate", parseFloat(e.target.value))} className="text-xs" />
                        </div>
                        <div>
                          <Label className="text-xs">GST %</Label>
                          <Select value={String(item.gst_rate ?? 18)} onValueChange={(v) => updateOcrLineItem(i, "gst_rate", Number(v))}>
                            <SelectTrigger className="text-xs h-8"><SelectValue /></SelectTrigger>
                            <SelectContent>
                              {GST_OPTIONS.map((r) => (
                                <SelectItem key={r} value={String(r)}>{r}%</SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                {ocrError && <p className="flex items-center gap-1.5 text-sm text-destructive"><AlertCircle className="h-4 w-4 shrink-0" />{ocrError}</p>}

                <div className="flex gap-2">
                  <Button variant="outline" onClick={() => { setOcrData(null); setOcrFile(null) }} className="flex-1">Re-scan</Button>
                  <Button onClick={handleOcrSave} disabled={ocrSaving} className="flex-1">
                    {ocrSaving ? <><Loader2 className="h-4 w-4 mr-2 animate-spin" />Saving…</> : "Save Invoice"}
                  </Button>
                </div>
              </div>
            )}
          </div>
        )}
      </SheetContent>
    </Sheet>
  )
}

import * as XLSX from "xlsx"
import { type ParsedBankRow, parseAmount, parseDate } from "./types"

// Parse an XLS or XLSX bank statement buffer into ParsedBankRow[]
//
// Handles three ICICI formats detected automatically:
//
// 1. ICICI Savings/Current Account XLS
//    Columns: Txn Date | Txn Remarks | Ref No./Cheque No. | Withdrawal Amt (INR) | Deposit Amt (INR) | Balance (INR)
//
// 2. ICICI Credit Card XLS (OpTransactionHistory / CCStatement)
//    Columns: Transaction Date | Transaction Details | Amount (in INR)
//    Amount is positive for charges, negative for payments/credits.
//
// 3. Generic bank XLS — auto-detected by header keyword matching
export function parseXlsBank(buffer: Buffer): ParsedBankRow[] {
  const workbook = XLSX.read(buffer, { type: "buffer", cellDates: true })

  const sheetName = workbook.SheetNames[0]
  const sheet = workbook.Sheets[sheetName]

  const aoa: unknown[][] = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: "" })

  // Find header row (first row containing "date" + some amount/remark column)
  let headerRow = -1
  for (let i = 0; i < Math.min(20, aoa.length); i++) {
    const rowStr = aoa[i].join(" ").toLowerCase()
    if (rowStr.includes("date") && (
      rowStr.includes("amount") || rowStr.includes("withdrawal") ||
      rowStr.includes("deposit") || rowStr.includes("debit") || rowStr.includes("credit")
    )) {
      headerRow = i
      break
    }
  }

  if (headerRow < 0) return []

  const headers = (aoa[headerRow] as string[]).map((h) =>
    String(h ?? "").toLowerCase().trim().replace(/\s+/g, " ")
  )

  const idx = (keys: string[]): number => {
    for (const k of keys) {
      const i = headers.findIndex((h) => h.includes(k))
      if (i >= 0) return i
    }
    return -1
  }

  const dateIdx    = idx(["txn date", "transaction date", "date", "value date"])
  const descIdx    = idx(["txn remarks", "transaction details", "description", "narration", "particulars", "remarks"])
  const refIdx     = idx(["ref no", "cheque no", "reference", "utr", "chq"])
  const debitIdx   = idx(["withdrawal amt", "debit", "withdrawal"])
  const creditIdx  = idx(["deposit amt", "credit", "deposit"])
  const amtIdx     = idx(["amount (in inr)", "amount"])   // single-column CC format
  const balanceIdx = idx(["balance"])

  if (dateIdx < 0) return []

  // Detect single-amount (credit card) vs split-amount (savings) mode
  const isCCMode = debitIdx < 0 && creditIdx < 0 && amtIdx >= 0

  const rows: ParsedBankRow[] = []

  for (let i = headerRow + 1; i < aoa.length; i++) {
    const row = aoa[i] as unknown[]

    const rawDate = row[dateIdx]
    if (!rawDate) continue

    let dateStr: string
    if (rawDate instanceof Date) {
      dateStr = rawDate.toISOString().split("T")[0]
    } else {
      dateStr = parseDate(String(rawDate))
    }

    const rawDesc = descIdx >= 0 ? String(row[descIdx] ?? "").trim() : ""

    let debit:  number | null = null
    let credit: number | null = null

    if (isCCMode) {
      // Credit card: positive = charge/debit, negative = payment/credit
      const rawAmt = parseAmount(String(row[amtIdx] ?? ""))
      if (rawAmt === null) continue
      if (rawAmt >= 0) {
        debit = rawAmt
      } else {
        credit = Math.abs(rawAmt)
      }
    } else {
      debit  = debitIdx  >= 0 ? parseAmount(String(row[debitIdx]  ?? "")) : null
      credit = creditIdx >= 0 ? parseAmount(String(row[creditIdx] ?? "")) : null
    }

    if (debit === null && credit === null) continue
    // Skip rows where both are zero (often subtotal rows)
    if ((debit ?? 0) === 0 && (credit ?? 0) === 0) continue

    rows.push({
      transaction_date: dateStr,
      description:      rawDesc,
      reference_number: refIdx >= 0 ? String(row[refIdx] ?? "").trim() || null : null,
      debit:  debit  && debit  > 0 ? debit  : null,
      credit: credit && credit > 0 ? credit : null,
      balance: balanceIdx >= 0 ? parseAmount(String(row[balanceIdx] ?? "")) : null,
    })
  }

  return rows
}

import { type ParsedBankRow, parseAmount, parseDate } from "./types"

// Parse a bank statement CSV file buffer into ParsedBankRow[]
//
// Handles three ICICI formats:
//
// 1. ICICI Savings/Current CSV
//    Columns: Transaction Date | Transaction Remarks | Value Date | Withdrawal Amount | Deposit Amount | Balance
//
// 2. ICICI Credit Card CSV (CreditCardStatement_icici.CSV)
//    Columns: Transaction Date | Transaction Details | Amount (in INR)
//    Amount: positive = charge, negative = payment/credit
//
// 3. Generic format with Date / Description / Debit / Credit / Balance
export function parseCsvBank(text: string): ParsedBankRow[] {
  const lines = text.split(/\r?\n/).filter((l) => l.trim())
  if (lines.length < 2) return []

  // Find header row
  let headerIdx = 0
  for (let i = 0; i < Math.min(15, lines.length); i++) {
    const lower = lines[i].toLowerCase()
    if (lower.includes("date") && (
      lower.includes("amount") || lower.includes("debit") ||
      lower.includes("withdrawal") || lower.includes("credit") || lower.includes("deposit")
    )) {
      headerIdx = i
      break
    }
  }

  const headers = splitCsvLine(lines[headerIdx])
    .map((h) => h.replace(/"/g, "").trim().toLowerCase())

  const idx = (keys: string[]): number => {
    for (const k of keys) {
      const i = headers.findIndex((h) => h.includes(k))
      if (i >= 0) return i
    }
    return -1
  }

  const dateIdx    = idx(["transaction date", "txn date", "date", "value date"])
  const descIdx    = idx(["transaction details", "txn remarks", "narration", "description", "particulars", "remarks"])
  const refIdx     = idx(["ref no", "cheque", "reference", "utr", "chq"])
  const debitIdx   = idx(["withdrawal", "debit"])
  const creditIdx  = idx(["deposit", "credit"])
  const amtIdx     = idx(["amount (in inr)", "amount"])   // single-column CC format
  const balanceIdx = idx(["balance", "closing balance"])

  if (dateIdx < 0) return []

  const isCCMode = debitIdx < 0 && creditIdx < 0 && amtIdx >= 0

  const rows: ParsedBankRow[] = []

  for (let i = headerIdx + 1; i < lines.length; i++) {
    const values = splitCsvLine(lines[i]).map((v) => v.replace(/"/g, "").trim())
    if (values.length < 2) continue

    const rawDate = values[dateIdx]
    if (!rawDate) continue

    let debit:  number | null = null
    let credit: number | null = null

    if (isCCMode) {
      const rawAmt = parseAmount(values[amtIdx])
      if (rawAmt === null) continue
      if (rawAmt >= 0) { debit = rawAmt } else { credit = Math.abs(rawAmt) }
    } else {
      debit  = debitIdx  >= 0 ? parseAmount(values[debitIdx])  : null
      credit = creditIdx >= 0 ? parseAmount(values[creditIdx]) : null
    }

    if (debit === null && credit === null) continue
    if ((debit ?? 0) === 0 && (credit ?? 0) === 0) continue

    rows.push({
      transaction_date: parseDate(rawDate),
      description:      descIdx >= 0 ? values[descIdx] : "",
      reference_number: refIdx  >= 0 ? values[refIdx]  || null : null,
      debit:  debit  && debit  > 0 ? debit  : null,
      credit: credit && credit > 0 ? credit : null,
      balance: balanceIdx >= 0 ? parseAmount(values[balanceIdx]) : null,
    })
  }

  return rows
}

function splitCsvLine(line: string): string[] {
  const result: string[] = []
  let current = ""
  let inQuotes = false
  for (const char of line) {
    if (char === '"') { inQuotes = !inQuotes }
    else if (char === "," && !inQuotes) { result.push(current); current = "" }
    else { current += char }
  }
  result.push(current)
  return result
}

